function out = fPolyfitFocusV01(x,y,range,peakX)%% Perform polyfit to particular case for focus%% out = fPolyfitFocusV01(x,y,range)%% x,y: x and y% range: [min max] for x to consider% peakX: x for the number%% out: y for peakX %%  %%%%%%%%%%%%%%%%%%%%%%%%%%%%% polyfit for focus, ver.1%% Kei Nakamura% Created on Friday, October 28th 2011.% Modified on %% ver.1: created%%%%%%%%%%%%%%%%%%%%%%%%%%%%% main bodyk = find(x>range(1)&x<range(2));x1 = x(k);y1 = y(k);p = polyfit(x1,y1,3);out = polyval(p,peakX);
